FIG_MED_A=(' ___                         ' '|   \ _ _ __ _ __ _ ___ _ _  ' '| |) | '\''_/ _` / _` / _ \ '\'' \ ' '|___/|_| \__,_\__, \___/_||_|' '              |___/          ')
