_pad(){ local n=$(( ($COLS-$1)/2 )); ((n<0)) && n=0; printf '%*s' "$n" ''; }
repeat(){ local s= i; for ((i=0;i<$2;i++)); do s+="$1"; done; printf '%s' "$s"; }
rule(){ local w=$1; printf '%s%s%s%s\n' "$(_pad $w)" "$C_FR" "$(repeat ‚ĒÄ $w)" "$RST"; }
center(){ printf '%s%b\n' "$(_pad $2)" "$1"; }

ANIM=false
draw_dragon(){ local -n _C=$1 _A=$2; local w=$3 i pad; pad=$(_pad "$w")
  for i in "${!_A[@]}"; do
    if [ "$TC" = 1 ]; then printf '%s\033[38;2;%sm%s%s\n' "$pad" "${_C[$i]}" "${_A[$i]}" "$RST"
    else printf '%s%s%s%s\n' "$pad" "$C_ACC" "${_A[$i]}" "$RST"; fi
    $ANIM && sleep 0.010; done; }
draw_fig(){ local -n _F=$1; local w=$2 i pad; pad=$(_pad "$w")
  for i in "${!_F[@]}"; do printf '%s%s%s%s\n' "$pad" "$BOLD$C_ACC" "${_F[$i]}" "$RST"; done; }

ok(){   printf '   %s[+]%s %s\n' "$C_OK"   "$RST" "$1"; }
bad(){  printf '   %s[x]%s %s\n' "$C_ERR"  "$RST" "$1"; }
warn(){ printf '   %s[!]%s %s\n' "$C_WARN" "$RST" "$1"; }
info(){ printf '   %s[>]%s %s\n' "$C_INFO" "$RST" "$1"; }

_row(){ local body="$5 $6"; local fill=$(( $3-1-${#body} )); ((fill<0)) && fill=0
  printf '%s%s‚Ēā%s %s%s%s %s%s%*s%s%s‚Ēā%s\n' "$1" "$2" "$RST" "$4" "$5" "$RST" "$BOLD" "$6" "$fill" '' "$RST" "$2" "$RST"; }
card(){ local col="$1" mk="$2" title="$3" msg="$4"
  local w=$(( COLS<60 ? COLS-2 : 56 )); ((w<24)) && w=$(( COLS-2 )); ((w<20)) && w=20; local inner=$(( w-2 ))
  local pad; pad=$(_pad "$w"); local bar; bar=$(repeat ‚ĒÄ "$inner")
  (( ${#title} > inner-5 )) && title="${title:0:inner-5}"
  (( ${#msg}   > inner-2 )) && msg="${msg:0:inner-3}‚Ä¶"
  printf '%s%s‚ĒĆ%s‚Ēź%s\n' "$pad" "$col" "$bar" "$RST"
  _row "$pad" "$col" "$inner" "$col" "$mk" "$title"
  local mfill=$(( inner-1-${#msg} )); ((mfill<0)) && mfill=0
  printf '%s%s‚Ēā%s %s%*s%s‚Ēā%s\n' "$pad" "$col" "$RST" "$msg" "$mfill" '' "$col" "$RST"
  printf '%s%s‚ĒĒ%s‚Ēė%s\n' "$pad" "$col" "$bar" "$RST"; }

run_step(){ local desc="$1"; shift
  if $SILENT || [ "$TC" = -1 ]; then
    if eval "$*" >"$LOG" 2>&1; then ok "$desc"; return 0; else bad "$desc"; return 1; fi; fi
  local fr='|/-\' i=0; ( eval "$*" >"$LOG" 2>&1 ) & local pid=$!
  while kill -0 "$pid" 2>/dev/null; do
    printf '\r   %s[%s]%s %s' "$C_INFO" "${fr:i:1}" "$RST" "$desc"; i=$(((i+1)%4)); sleep 0.09; done
  wait "$pid"; local rc=$?
  if [ $rc -eq 0 ]; then printf '\r   %s[+]%s %s\033[K\n' "$C_OK" "$RST" "$desc"
  else printf '\r   %s[x]%s %s\033[K\n' "$C_ERR" "$RST" "$desc"; fi; return $rc; }

name_fallback(){ if [ "$COLS" -ge 11 ]; then center "${BOLD}${C_ACC}D R A G O N${RST}" 11; else center "${BOLD}${C_ACC}DRAGON${RST}" 6; fi; }
show_logo(){ $SILENT && return; [ "$TC" != -1 ] && ANIM=true
  [ "$DRAGON_DEBUG" = 1 ] && printf '%s[debug COLS=%s]%s\n' "$C_DIM" "$COLS" "$RST" >&2
  echo
  # pick the LARGEST art whose width fits COLS -> can never overflow
  if   [ "$COLS" -ge "$DBIG_W" ]; then draw_dragon DBIG_C DBIG_A "$DBIG_W"; echo
       if [ "$COLS" -ge "$FIG_BIG_W" ]; then draw_fig FIG_BIG_A "$FIG_BIG_W"; else name_fallback; fi
  elif [ "$COLS" -ge "$DMED_W" ]; then draw_dragon DMED_C DMED_A "$DMED_W"; echo
       if [ "$COLS" -ge "$FIG_MED_W" ]; then draw_fig FIG_MED_A "$FIG_MED_W"; else name_fallback; fi
  elif [ "$COLS" -ge "$DSML_W" ]; then draw_dragon DSML_C DSML_A "$DSML_W"; echo; name_fallback
  else name_fallback; fi
  ANIM=false; echo
  local tag="Termux Repository  ‚ÄĘ  204 curated tools"
  (( ${#tag} > COLS-2 )) && tag="204 curated tools"
  (( ${#tag} > COLS-2 )) && tag="Dragon"
  printf '%s%s%s%s\n\n' "$(_pad ${#tag})" "$C_DIM" "$tag" "$RST"; }

main(){ clear 2>/dev/null; show_logo
  rule $(( COLS<58?COLS-2:56 )); echo
  info "Setting up the ${BOLD}Dragon${RST} repository‚Ä¶"; echo
  if [ -f "$PREFIX/etc/apt/sources.list.d/x11.list" ]; then ok "X11 repository present"
  else run_step "Installing X11 repository" "apt install x11-repo -y" || warn "X11 repo failed (continuing)"; fi
  if [ -f "$PREFIX/etc/apt/sources.list.d/glibc.list" ]; then ok "glibc repository present"
  else run_step "Installing glibc repository" "apt install glibc-repo -y" || warn "glibc repo optional (skipped)"; fi
  run_step "Creating sources directory" "mkdir -p \$PREFIX/etc/apt/sources.list.d" \
    || { echo; card "$C_ERR" "[x]" "Fatal error" "Cannot create sources dir"; exit 1; }
  run_step "Adding Dragon repository" \
    "echo 'deb [trusted=yes arch=all] https://aliheba125.github.io/repo termuxvoid main' > \$PREFIX/etc/apt/sources.list.d/termuxvoid.list" \
    || { echo; card "$C_ERR" "[x]" "Fatal error" "Cannot write sources.list"; exit 1; }
  run_step "Importing signing key" \
    "curl -fsSL https://github.com/aliheba125/repo/raw/main/assets/termuxvoid.gpg -o \$PREFIX/etc/apt/trusted.gpg.d/termuxvoid.gpg" \
    || warn "Key skipped ‚ÄĒ repo is [trusted=yes]"
  if run_step "Updating package lists" "apt update -y"; then
    echo; card "$C_OK" "[+]" "Dragon is ready!" "apt install <pkg>"; echo
    info "List:  ${C_ACC}apt list 2>/dev/null|grep termuxvoid${RST}"
    info "TG:    ${C_ACC}t.me/a1002a${RST}"
    info "WA:    ${C_ACC}wa.me/9647823210125${RST}"
  else echo; card "$C_WARN" "[!]" "Finished with warnings" "Run 'apt update' to retry"; fi
  echo; rule $(( COLS<58?COLS-2:56 ))
  center "${C_DIM}>> happy hacking with Dragon${RST}" 28; echo; }

if [ "$DRAGON_DEMO" = 1 ]; then
  clear 2>/dev/null; show_logo; rule $(( COLS<58?COLS-2:56 )); echo
  ok "X11 repository present"; info "Adding the Dragon repository‚Ä¶"
  warn "Key download slow ‚ÄĒ retrying"; bad "Network unreachable"; echo
  card "$C_OK"   "[+]" "Dragon is ready!"       "apt install <package>"; echo
  card "$C_WARN" "[!]" "Finished with warnings" "Run 'apt update' to retry"; echo
  card "$C_ERR"  "[x]" "Installation failed"    "Check your connection"; echo
  info "TG:  ${C_ACC}t.me/a1002a${RST}"
  info "WA:  ${C_ACC}wa.me/9647823210125${RST}"; echo
  exit 0
fi
main
